/-- Bounded potential outcomes: `|Y_i^1| ≤ 1` and `|Y_i^0| ≤ 1`. -/
def BoundedOutcomes (E : BipartiteExperiment I O) : Prop :=
  ∀ i, |E.Y1 i| ≤ 1 ∧ |E.Y0 i| ≤ 1
